import{_ as t,o,c as a,a2 as r}from"./chunks/framework.BWuWLRhz.js";const u=JSON.parse('{"title":"RFC 0021 — Platform roles & capabilities","description":"","frontmatter":{},"headers":[],"relativePath":"rfcs/0021-platform-roles-and-capabilities.md","filePath":"rfcs/0021-platform-roles-and-capabilities.md"}'),n={name:"rfcs/0021-platform-roles-and-capabilities.md"};function i(s,e,d,l,c,g){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="rfc-0021-—-platform-roles-capabilities" tabindex="-1">RFC 0021 — Platform roles &amp; capabilities <a class="header-anchor" href="#rfc-0021-—-platform-roles-capabilities" aria-label="Permalink to &quot;RFC 0021 — Platform roles &amp; capabilities&quot;">​</a></h1><p><strong>Status:</strong> Accepted<br><strong>Date:</strong> June 2026<br><strong>Author:</strong> kasunben<br><strong>Scope:</strong> <code>apps/auth</code> (role default → owner, first-user hook, role-change guards), a centralized roles/capabilities module, <code>runtime/src/route-guard.ts</code> + <code>runtime/middleware.ts</code> + <code>runtime/src/session-verify.ts</code> (capability gate + capabilities in the session cache), <code>runtime/src/launcher-plugins.ts</code> + <code>(platform)/layout.tsx</code> (chrome gating), <code>packages/sdk</code> (<code>SessionUser</code> + <code>hasCapability</code>/<code>requireCapability</code>), <code>packages/manifest</code> (<code>adminOnly</code> → capability, the reserved <code>admin:*</code>), Console (role management UI), SRS §3.4 / AUTH-08 / PLT-03 / CON-05; builds on RFC 0005 (audit), RFC 0008 (security)<br><strong>Incorporated into plan:</strong> Yes — scheduled as roadmap Task 0.6.0; documentation-first. This RFC specifies the platform role/capability model and the end-to-end flows; SRS requirement IDs, scheduling, and task allocation are deferred. <strong>Plugin-declared capabilities are RFC 0022</strong>, which builds on this one.</p><hr><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>Grow Sovereign&#39;s two-role model (<code>platform:admin</code> / <code>platform:user</code>) into a <strong>capability-based</strong> model so an owner can delegate <em>some</em> administration without handing over everything:</p><ul><li><strong>Capabilities are the enforcement unit</strong> (<code>console:access</code>, <code>user:manage</code>, <code>plugin:manage</code>, <code>tenant:configure</code>, <code>health:view</code>, …).</li><li><strong>Roles are named presets</strong> = capability bundles, with <strong>hardcoded defaults</strong> that work with zero config and an optional <strong>DB-driven override</strong> layer for customization.</li><li>Built-in roles: <strong>owner</strong>, <strong>admin</strong>, <strong>auditor</strong>, <strong>user</strong>.</li><li>A protected <strong><code>platform:owner</code></strong> super-admin sits on top — the first user, the sole holder of role assignment, and impossible to lock out (which also fixes today&#39;s missing last-admin guard).</li></ul><p>This is not a new direction: <strong>SRS §3.4 already specified a Role &amp; Capability Model</strong> and explicitly designed the data model &quot;to support database-driven capability assignment in a future version without requiring a schema change.&quot; This RFC is that future version.</p><h2 id="motivation" tabindex="-1">Motivation <a class="header-anchor" href="#motivation" aria-label="Permalink to &quot;Motivation&quot;">​</a></h2><p>A growing self-hosted instance needs middle-ground administrators — a read-only <strong>auditor</strong> for oversight, an operational helper who can manage plugins but not users — and a protected <strong>owner</strong> so admins can be added without risking lockout. Today everything is binary: you&#39;re <code>platform:admin</code> (can do everything) or <code>platform:user</code> (can do nothing administrative), and an admin can demote or deactivate the last admin with no guard. The capability model the SRS already sketched closes this gap.</p><h2 id="current-state-what-this-builds-on" tabindex="-1">Current state (what this builds on) <a class="header-anchor" href="#current-state-what-this-builds-on" aria-label="Permalink to &quot;Current state (what this builds on)&quot;">​</a></h2><ul><li><strong>Two roles, binary enforcement.</strong> <code>role</code> is a better-auth <code>additionalField</code> defaulting to <code>platform:user</code>; the first user becomes <code>platform:admin</code> (<code>apps/auth/src/auth.ts</code>). Enforcement is <code>role === &#39;platform:admin&#39;</code> in ~6 places: <code>route-guard.ts</code> (<code>adminOnly &amp;&amp; role !== &#39;platform:admin&#39; → 403</code>), the launcher filter (<code>launcher-plugins.ts</code>), and <code>(platform)/layout.tsx</code> (<code>isAdmin</code> chrome).</li><li><strong>Role is a bare string, scattered.</strong> <code>&#39;platform:admin&#39;</code> / <code>&#39;platform:user&#39;</code> are hardcoded literals in ~50 sites — <strong>not centralized, not a typed union</strong>. Step one is centralizing.</li><li><strong>Propagation.</strong> Verified role → signed <code>session_data</code> cookie cache → <code>x-sovereign-user-role</code> header → <code>sdk.auth.getSession().user.role</code>. Plugins <strong>string-compare</strong> (<code>role === &#39;platform:admin&#39;</code>); there is <strong>no helper</strong>.</li><li><strong>Mutation, no last-admin guard.</strong> Console → admin-key API (<code>apps/auth/app/api/admin/users/[id]</code> PATCH) changes role with <strong>no</strong> check against demoting/deactivating the last admin.</li><li><strong>Two distinct &quot;admin&quot; concepts — do not conflate.</strong> <code>SOVEREIGN_ADMIN_KEY</code> is a <strong>server-to-server secret</strong> (runtime↔auth, <code>admin-guard.ts</code>); <code>platform:admin</code> is a <strong>user role</strong>. This RFC concerns only the role.</li><li><strong>SRS §3.4 is the anchor.</strong> It defines the capability matrix (<code>console:access</code>, <code>user:manage</code>, <code>plugin:manage</code>, <code>tenant:configure</code>, <code>plugin:access</code>, <code>profile:manage</code>), states <em>&quot;capabilities are hardcoded per role in v1… the data model is designed to support database-driven capability assignment in a future version without requiring a schema change,&quot;</em> defers <em>&quot;granular per-user capability overrides,&quot;</em> and chose <code>platform:</code> namespacing to <em>&quot;scale to plugin-level roles.&quot;</em> The reserved <code>admin:*</code> manifest permission was noted for &quot;future fine-grained plugin admin scopes.&quot;</li></ul><h2 id="proposed-design" tabindex="-1">Proposed design <a class="header-anchor" href="#proposed-design" aria-label="Permalink to &quot;Proposed design&quot;">​</a></h2><h3 id="capabilities-the-enforcement-unit" tabindex="-1">Capabilities (the enforcement unit) <a class="header-anchor" href="#capabilities-the-enforcement-unit" aria-label="Permalink to &quot;Capabilities (the enforcement unit)&quot;">​</a></h3><p>Define a capability set with <strong>read/write granularity</strong> so an auditor is meaningful, derived from the SRS matrix + the four Console areas (users / plugins / settings / health):</p><p><code>plugin:access</code>, <code>profile:manage</code>, <code>console:access</code>, <code>user:view</code>, <code>user:manage</code>, <code>plugin:manage</code>, <code>tenant:view</code>, <code>tenant:configure</code>, <code>health:view</code>, <code>activity:view</code> (the RFC 0005 audit log), <code>role:assign</code> (owner-only).</p><h3 id="built-in-role-presets-hardcoded-defaults" tabindex="-1">Built-in role presets (hardcoded defaults) <a class="header-anchor" href="#built-in-role-presets-hardcoded-defaults" aria-label="Permalink to &quot;Built-in role presets (hardcoded defaults)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Capability</th><th style="text-align:center;">user</th><th style="text-align:center;">auditor</th><th style="text-align:center;">admin</th><th style="text-align:center;">owner</th></tr></thead><tbody><tr><td><code>plugin:access</code></td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td></tr><tr><td><code>profile:manage</code></td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td></tr><tr><td><code>console:access</code></td><td style="text-align:center;"></td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td></tr><tr><td><code>user:view</code></td><td style="text-align:center;"></td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td></tr><tr><td><code>tenant:view</code></td><td style="text-align:center;"></td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td></tr><tr><td><code>health:view</code></td><td style="text-align:center;"></td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td></tr><tr><td><code>activity:view</code></td><td style="text-align:center;"></td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td></tr><tr><td><code>user:manage</code></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td></tr><tr><td><code>plugin:manage</code></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td></tr><tr><td><code>tenant:configure</code></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;">✓</td><td style="text-align:center;">✓</td></tr><tr><td><code>role:assign</code></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;"></td><td style="text-align:center;">✓</td></tr></tbody></table><ul><li><strong>owner</strong> — every capability, incl. <code>role:assign</code>; protected.</li><li><strong>admin</strong> — all operational + <code>*:view</code>; <strong>not</strong> <code>role:assign</code> (the owner assigns).</li><li><strong>auditor</strong> — read-only oversight; no mutations.</li><li><strong>user</strong> — the floor (use plugins, manage own profile).</li></ul><h3 id="db-driven-override-customization" tabindex="-1">DB-driven override (customization) <a class="header-anchor" href="#db-driven-override-customization" aria-label="Permalink to &quot;DB-driven override (customization)&quot;">​</a></h3><p>Effective capabilities resolve as: <strong>the role&#39;s hardcoded default preset → overridden by DB-stored customizations</strong> when present. Zero config yields the presets; customization is optional. <code>devops</code> is the worked example of a <strong>custom role</strong> an owner creates by granting <code>plugin:manage</code> + <code>tenant:configure</code> + <code>health:view</code> (no user management) — demonstrating the override layer without hardcoding the role. <em>Override granularity — per-role redefinition vs per-user grants/revokes vs both — is an open question; the resolver is designed for both.</em></p><h3 id="the-edge-gate-wrinkle-key-design-point" tabindex="-1">The Edge-gate wrinkle (key design point) <a class="header-anchor" href="#the-edge-gate-wrinkle-key-design-point" aria-label="Permalink to &quot;The Edge-gate wrinkle (key design point)&quot;">​</a></h3><p>The route gate runs in <strong>Edge middleware, which cannot read the database</strong>, so DB-driven overrides can&#39;t be consulted there. Proposed mechanism: compute a user&#39;s <strong>effective capabilities server-side</strong> (where the role preset + DB overrides are known) and <strong>carry them in the signed <code>session_data</code> cookie cache</strong> alongside <code>role</code>, so the Edge middleware reads them <strong>offline</strong> — the same trust model as role today (AUTH-05). Staleness is bounded by the cookie-cache <code>maxAge</code> (300s), exactly like a role or active-status change. Trade-off: a slightly larger signed cookie. (Rejected alternative: a coarse role gate at the Edge with fine capability checks only in Node — it can&#39;t enforce capability <em>reductions</em> at the route boundary.)</p><h3 id="platform-owner-specifics" tabindex="-1"><code>platform:owner</code> specifics <a class="header-anchor" href="#platform-owner-specifics" aria-label="Permalink to &quot;`platform:owner` specifics&quot;">​</a></h3><p>The <strong>first user becomes <code>platform:owner</code></strong> (amends AUTH-08). The owner holds every capability, is the <strong>sole holder of <code>role:assign</code></strong>, and is <strong>protected</strong> — cannot be demoted, deactivated, or locked out, which closes today&#39;s last-admin gap. <em>Open: exactly one owner vs several; an ownership-<strong>transfer</strong> operation; migration for existing instances (the current first admin becomes owner).</em></p><h3 id="enforcement-changes" tabindex="-1">Enforcement changes <a class="header-anchor" href="#enforcement-changes" aria-label="Permalink to &quot;Enforcement changes&quot;">​</a></h3><ul><li><strong>Centralize</strong> role + capability constants and a <code>hasCapability(user, cap)</code> / <code>requireCapability(cap)</code> resolver, replacing the ~50 string literals and the 6 binary checks.</li><li><code>route-guard</code>&#39;s <code>adminOnly</code> → requires a generic admin capability (<code>console:access</code>); the launcher filter and chrome gating switch to capability checks.</li><li><em>Future/extension:</em> a plugin may declare which capability its <code>adminOnly</code> requires (ties to the reserved <code>admin:*</code>).</li></ul><h3 id="sdk-surface" tabindex="-1">SDK surface <a class="header-anchor" href="#sdk-surface" aria-label="Permalink to &quot;SDK surface&quot;">​</a></h3><p><code>SessionUser</code> gains <code>capabilities</code> (keeping <code>role</code>); <code>sdk.auth</code> adds <code>hasCapability(cap)</code> / <code>requireCapability(cap)</code> so plugins stop string-comparing. Additive <strong>minor</strong> SDK bump.</p><h2 id="ui-flows" tabindex="-1">UI / flows <a class="header-anchor" href="#ui-flows" aria-label="Permalink to &quot;UI / flows&quot;">​</a></h2><p>The <strong>owner</strong> opens Console → Users → assigns a role (owner / admin / auditor / user) and optionally customizes capabilities → the assignment is <strong>audited</strong> (RFC 0005). An <strong>auditor</strong> sees a read-only Console (no mutate controls; mutations 403). A user lacking a capability is <strong>403</strong>&#39;d at the gate. The <strong>owner row is un-editable</strong> by anyone else.</p><h2 id="alternatives-considered" tabindex="-1">Alternatives considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives considered&quot;">​</a></h2><ol><li><strong>Fixed named roles only</strong> (no capability layer). Rejected — every new admin-area gate would hardcode a role list, drifting from the SRS capability model; rejected by the user.</li><li><strong>Full per-user RBAC with no presets.</strong> Rejected for v1 — the SRS defers per-user overrides, and zero-config presets are the simpler default. (Per-user overrides remain a later phase on top of the same resolver.)</li><li><strong>Keep flat admin + only add a last-admin guard.</strong> Rejected — no delegation, no auditor; the owner tier subsumes the guard anyway.</li><li><strong>Resolve capabilities by DB at the Edge.</strong> Rejected — middleware can&#39;t read the DB; hence capabilities-in-the-cookie.</li></ol><h2 id="open-questions" tabindex="-1">Open questions <a class="header-anchor" href="#open-questions" aria-label="Permalink to &quot;Open questions&quot;">​</a></h2><ol><li><strong>Override granularity</strong> — per-role redefinition vs per-user grants/revokes vs both; v1 scope.</li><li><strong>Owner</strong> — single vs multiple; transfer operation; existing-instance migration.</li><li><strong>Capabilities in the cookie</strong> — size/staleness trade-off vs alternatives.</li><li><strong>Assignment scope</strong> — may <code>admin</code> assign roles below itself, or only the owner?</li><li><strong>Plugin-level roles</strong> (<code>tasks:admin</code>) — how they layer on (→ RFC 0022).</li><li><strong>Requirement IDs</strong> — AUTH-/PLT-/CON- successors, deferred until accepted.</li></ol><h2 id="adoption-path" tabindex="-1">Adoption path <a class="header-anchor" href="#adoption-path" aria-label="Permalink to &quot;Adoption path&quot;">​</a></h2><ol><li><strong>Documentation-first (this RFC).</strong></li><li><strong>When accepted &amp; scheduled:</strong> centralize roles/capabilities + the resolver + carry capabilities in the session cache; introduce <code>platform:owner</code> (+ the AUTH-08 amendment + migration); the auditor preset; capability-based gating; the SDK helper; and the Console assignment UI. The <strong>DB-override customization</strong> layer and <strong>per-user overrides</strong> are sequenced as later phases.</li><li><strong>RFC 0022 — Plugin-declared capabilities</strong> builds on this foundation.</li></ol><h2 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Version</th><th>Date</th><th>Change</th></tr></thead><tbody><tr><td>0.1</td><td>Jun 2026</td><td>Initial draft; capability-based model with owner/admin/auditor/user presets (hardcoded defaults + DB-driven override), a protected <code>platform:owner</code>, capabilities carried in the session cache for Edge gating; anchored on SRS §3.4; documentation-first.</td></tr><tr><td>0.2</td><td>Jun 2026</td><td>Accepted; scheduled in the roadmap as Task 0.6.0.</td></tr></tbody></table>',38)])])}const p=t(n,[["render",i]]);export{u as __pageData,p as default};
